plugin.generateCode:
const now = Date.now();
const fmt = options.format ?? 'iso';
const utc = options.utc !== false;
const count = Math.max(1, Math.min(50, Number(options.count ?? 1)));
const results = [];
for (let i = 0; i < count; i++) {
  const t = now + i;
  const d = new Date(t);
  if (fmt === 'unix-ms') results.push(String(t));
  else if (fmt === 'unix-s') results.push(String(Math.floor(t / 1000)));
  else if (fmt === 'rfc2822') results.push(d.toUTCString());
  else if (fmt === 'date-only') results.push(utc ? d.toISOString().slice(0, 10) : d.toLocaleDateString());
  else if (fmt === 'time-only') results.push(utc ? d.toISOString().slice(11, 19) + 'Z' : d.toLocaleTimeString());
  else results.push(utc ? d.toISOString() : d.toString());
}
return { output: results.join('\n'), outputLanguage: 'text' };
